const fs = require('fs');
const path = require('path');
const watchedRoot = '/home/node/.n8n-files/crispybrain/inbox';
const statePath = '/home/node/.n8n/auto-ingest-watch-state.json';
const slugPattern = /^[a-z0-9]+(?:[-_][a-z0-9]+)*$/;
const readState = () => {
  try {
    const parsed = JSON.parse(fs.readFileSync(statePath, 'utf8'));
    if (parsed && typeof parsed === 'object' && parsed.files && typeof parsed.files === 'object') {
      return { initialized: parsed.initialized === true, files: parsed.files };
    }
  } catch (error) {}
  return { initialized: false, files: {} };
};
const writeState = (state) => {
  fs.writeFileSync(statePath, JSON.stringify(state, null, 2));
};
const listTrackedFiles = () => {
  const discovered = [];
  if (!fs.existsSync(watchedRoot)) {
    return discovered;
  }
  for (const entry of fs.readdirSync(watchedRoot, { withFileTypes: true })) {
    if (!entry.isDirectory()) {
      continue;
    }
    const projectSlug = entry.name;
    if (!slugPattern.test(projectSlug)) {
      continue;
    }
    const projectDir = path.join(watchedRoot, projectSlug);
    for (const fileEntry of fs.readdirSync(projectDir, { withFileTypes: true })) {
      if (!fileEntry.isFile()) {
        continue;
      }
      if (!/\.txt$/i.test(fileEntry.name)) {
        continue;
      }
      const containerPath = path.join(projectDir, fileEntry.name);
      const stat = fs.statSync(containerPath);
      discovered.push({
        projectSlug,
        filename: fileEntry.name,
        containerPath,
        relativePath: `${projectSlug}/${fileEntry.name}`,
        signature: `${stat.mtimeMs}:${stat.size}`,
      });
    }
  }
  return discovered.sort((a, b) => a.containerPath.localeCompare(b.containerPath));
};
const state = readState();
const discovered = listTrackedFiles();
const currentPaths = new Set(discovered.map((item) => item.containerPath));
let stateChanged = false;
for (const trackedPath of Object.keys(state.files)) {
  if (!currentPaths.has(trackedPath)) {
    delete state.files[trackedPath];
    stateChanged = true;
  }
}
if (!state.initialized) {
  for (const item of discovered) {
    state.files[item.containerPath] = item.signature;
  }
  state.initialized = true;
  writeState(state);
  return [];
}
const outputs = [];
for (const item of discovered) {
  if (state.files[item.containerPath] === item.signature) {
    continue;
  }
  const runId = 'auto-ingest-watch-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
  const timestamp = new Date().toISOString();
  outputs.push({
    json: {
      container_path: item.containerPath,
      relative_path: item.relativePath,
      filename: item.filename,
      project_slug: item.projectSlug,
      source_type: 'file_watch',
      file_signature: item.signature,
      state_path: statePath,
      trace: {
        run_id: runId,
        correlation_id: runId,
        workflow_name: 'auto-ingest-watch',
        project_slug: item.projectSlug,
        source_type: 'file_watch',
        filename: item.filename,
        filepath: item.containerPath,
        stage: 'detected',
        status: 'accepted',
        error_code: null,
        error_message: null,
        timestamp,
        workflow_chain: ['auto-ingest-watch'],
        stage_history: [
          {
            stage: 'detected',
            status: 'accepted',
            timestamp,
            error_code: null,
            error_message: null
          }
        ]
      }
    }
  });
}
if (stateChanged) {
  writeState(state);
}
return outputs;

const fs = require('fs');
const base = $('Discover Pending Files').item.json;
const content = fs.readFileSync(base.container_path, 'utf8').replace(/\r\n/g, '\n');
const withStage = (trace, stage, status, extra = {}) => {
  const timestamp = new Date().toISOString();
  const errorCode = Object.prototype.hasOwnProperty.call(extra, 'error_code') ? extra.error_code : (trace.error_code ?? null);
  const errorMessage = Object.prototype.hasOwnProperty.call(extra, 'error_message') ? extra.error_message : (trace.error_message ?? null);
  return {
    ...trace,
    ...extra,
    stage,
    status,
    error_code: errorCode,
    error_message: errorMessage,
    timestamp,
    stage_history: [
      ...(Array.isArray(trace.stage_history) ? trace.stage_history : []),
      { stage, status, timestamp, error_code: errorCode, error_message: errorMessage },
    ],
  };
};
return {
  json: {
    filepath: base.container_path,
    filename: base.filename,
    content,
    project_slug: base.project_slug,
    source_type: base.source_type,
    file_signature: base.file_signature,
    state_path: base.state_path,
    trace: withStage(base.trace, 'payload_ready', 'accepted'),
  },
};

const fs = require('fs');
const request = $('Build Ingest Payload').item.json;
const statusCode = $json.statusCode ?? 0;
const rawBody = $json.body ?? {};
const body = Array.isArray(rawBody) ? (rawBody[0] ?? {}) : rawBody;
const ok = statusCode >= 200 && statusCode < 300 && body.ok === true;
let state = { initialized: true, files: {} };
try {
  const parsed = JSON.parse(fs.readFileSync(request.state_path, 'utf8'));
  if (parsed && typeof parsed === 'object' && parsed.files && typeof parsed.files === 'object') {
    state = { initialized: parsed.initialized === true, files: parsed.files };
  }
} catch (error) {}
if (ok) {
  state.files[request.filepath] = request.file_signature;
  fs.writeFileSync(request.state_path, JSON.stringify(state, null, 2));
}
return {
  json: {
    ok,
    statusCode,
    watched_path: request.filepath,
    filename: request.filename,
    project_slug: request.project_slug,
    ingest_response_ok: body.ok ?? null,
    ingest_workflow: body.trace?.workflow_name ?? null,
    ingest_stage: body.trace?.stage ?? null,
    duplicate_detected: body.duplicate_detected ?? null,
    error: ok ? null : (body.error ?? { code: 'UPSTREAM_HTTP_ERROR', message: 'Canonical ingest webhook failed' }),
  },
};
